{
  "$schema": "https://json-schema.org/draft-07/schema#",
  "$id": "https://harness.local/system-spec-harness/completeness-findings.schema.json",
  "title": "system-spec completeness evaluation report (C05)",
  "description": "生成された仕様書ドキュメントセットの完成度評価レポート。上位概念・意思決定・網羅性・deep knowledge・鮮度・prompt品質の観点 + 総合判定をfail-closedに再導出し、独立auditor帰属を実fork証跡へ接地させる。",
  "type": "object",
  "additionalProperties": false,
  "required": ["evaluator", "verdict", "aspects", "audit_delegations", "findings", "gaps"],
  "properties": {
    "evaluator": {
      "type": "object",
      "additionalProperties": false,
      "required": ["name", "version", "context"],
      "properties": {
        "name": {"const": "assign-system-spec-completeness-evaluator"},
        "version": {"type": "string", "minLength": 1},
        "context": {"const": "fork"}
      }
    },
    "spec_dir": {"type": "string"},
    "verdict": {"type": "string", "enum": ["PASS", "FAIL"]},
    "aspects": {
      "type": "object",
      "additionalProperties": false,
      "required": ["foundation_trace", "decision_guidance", "matrix_coverage", "design_knowledge_reflection", "doc_freshness", "prompt_quality"],
      "properties": {
        "foundation_trace": {"$ref": "#/definitions/aspect"},
        "decision_guidance": {"$ref": "#/definitions/aspect"},
        "matrix_coverage": {"$ref": "#/definitions/aspect"},
        "design_knowledge_reflection": {"$ref": "#/definitions/aspect"},
        "doc_freshness": {"$ref": "#/definitions/aspect"},
        "prompt_quality": {"$ref": "#/definitions/aspect"}
      }
    },
    "audit_delegations": {
      "type": "array",
      "description": "独立 context (Task fork) で起動した監査 sub-agent の receipt 一覧。auditor が C05 自身でない観点 (primary) と、宣言された sub-input 監査 (matrix_coverage の C06) に 1 件ずつ必須。PostToolUse hook が書く fork 台帳と突合され、裏取りできない帰属は fail-closed で violation になる。",
      "items": {"$ref": "#/definitions/audit_delegation"}
    },
    "gate_results": {
      "type": "array",
      "items": {"$ref": "#/definitions/gate_result"}
    },
    "findings": {
      "type": "array",
      "minItems": 1,
      "items": {"$ref": "#/definitions/finding"}
    },
    "gaps": {
      "type": "array",
      "items": {"type": "string", "minLength": 1},
      "description": "不足事項一覧。verdict=FAIL のとき非空 (elicit/doc-fetch/compile への差し戻し材料)。"
    }
  },
  "definitions": {
    "aspect": {
      "type": "object",
      "additionalProperties": false,
      "required": ["verdict", "auditor", "component", "summary"],
      "properties": {
        "verdict": {"type": "string", "enum": ["PASS", "FAIL", "INDETERMINATE"]},
        "score": {"type": "number", "minimum": 0, "maximum": 100},
        "auditor": {"type": "string", "minLength": 1},
        "component": {"type": "string", "minLength": 1},
        "summary": {"type": "string", "minLength": 1},
        "evidence": {"type": "array", "items": {"type": "string"}}
      }
    },
    "audit_delegation": {
      "type": "object",
      "additionalProperties": false,
      "required": ["aspect", "role", "auditor", "component", "dispatch", "verdict", "evidence"],
      "properties": {
        "aspect": {"type": "string", "enum": ["foundation_trace", "decision_guidance", "matrix_coverage", "design_knowledge_reflection", "doc_freshness", "prompt_quality"]},
        "role": {"type": "string", "enum": ["primary", "sub_input"], "description": "primary=当該観点の一次根拠 / sub_input=補助根拠 (独立観点へ昇格させない)"},
        "auditor": {"type": "string", "minLength": 1, "description": "plugin 同梱の agent 定義 (agents/<auditor>.md) に実在する名前"},
        "component": {"type": "string", "minLength": 1},
        "dispatch": {
          "type": "object",
          "additionalProperties": false,
          "required": ["tool", "subagent_type"],
          "properties": {
            "tool": {"enum": ["Task", "Agent"], "description": "subagent 起動ツール名の観測値 (旧ハーネス/Codex 系='Task', 現行 Claude Code='Agent')。aggregate-completeness.py の LEDGER_TOOL_NAMES と整合"},
            "subagent_type": {"type": "string", "minLength": 1, "description": "auditor と一致すること。fork 台帳の subagent_type と突合される"}
          }
        },
        "verdict": {"type": "string", "enum": ["PASS", "FAIL", "INDETERMINATE"], "description": "role=primary のとき aspects[aspect].verdict と一致必須 (監査判定の忠実転記)"},
        "evidence": {"type": "array", "minItems": 1, "items": {"type": "string", "minLength": 1}}
      }
    },
    "gate_result": {
      "type": "object",
      "additionalProperties": false,
      "required": ["id", "name", "exit_code"],
      "properties": {
        "id": {"type": "string", "minLength": 1},
        "name": {"type": "string", "minLength": 1},
        "conditions": {"type": "array", "items": {"type": "string"}},
        "command": {"type": "array", "items": {"type": "string"}},
        "exit_code": {"type": "integer"},
        "stdout": {"type": "string"},
        "stderr": {"type": "string"}
      }
    },
    "finding": {
      "type": "object",
      "additionalProperties": false,
      "required": ["severity", "bucket", "observation"],
      "properties": {
        "severity": {"type": "string", "enum": ["high", "medium", "low", "info"]},
        "bucket": {"type": "string", "minLength": 1},
        "observation": {"type": "string", "minLength": 1},
        "suggested_fix": {"type": "string"},
        "evidence": {"type": "array", "items": {"type": "string"}}
      }
    }
  }
}

